Step 4: Implement the report page UI exactly as plan:
```tsx
import { useEffect, useState } from 'react';
import type { ReportSpec } from '@openfons/contracts';
import { createReportLoader, type ReportLoader } from '../api';

type Props = {
  reportId: string;
  loadReport?: ReportLoader;
};

export const ReportPage = ({
  reportId,
  loadReport = createReportLoader(import.meta.env.VITE_CONTROL_API_BASE_URL ?? 'http://localhost:3001')
}: Props) => {
  const [report, setReport] = useState<ReportSpec | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;

    loadReport(reportId)
      .then((next) => {
        if (!cancelled) {
          setReport(next);
        }
      })
      .catch((caught) => {
        if (!cancelled) {
          setError(caught instanceof Error ? caught.message : 'Unknown error');
        }
      });

    return () => {
      cancelled = true;
    };
  }, [loadReport, reportId]);

  if (error) {
    return <p className="page-shell">{error}</p>;
  }

  if (!report) {
    return <p className="page-shell">Loading report...</p>;
  }

  return (
    <main className="page-shell">
      <section className="hero-card">
        <p className="eyebrow">OpenFons Report Delivery</p>
        <h1>{report.title}</h1>
        <p>{report.summary}</p>
      </section>
      {report.sections.map((section) => (
        <article className="section-card" key={section.id}>
          <h2>{section.title}</h2>
          <p>{section.body}</p>
        </article>
      ))}
    </main>
  );
};
```

Step 5: Add router, entry point, and styles exactly as plan:
- `src/router.tsx`: root layout with `<Outlet />`; `/` route renders `<p className="page-shell">Open a report at /reports/$reportId</p>`; `/reports/$reportId` route reads params via `reportRoute.useParams()` and renders `ReportPage`; export `router`; declare Register module
- `src/main.tsx`: render `RouterProvider` inside `React.StrictMode`; import `./styles.css`
- `src/styles.css` exactly use the plan’s minimal serif stylesheet/selectors/values

Step 6: Install dependencies and verify:
- `pnpm install`
- `pnpm test -- tests/smoke/report-web.test.tsx`
- `pnpm --filter @openfons/report-web build`
- `pnpm --filter @openfons/report-web lint`
Expected: React deps install, smoke test passes, Vite build succeeds, TS no errors.

Step 7: Commit:
- `git add apps/report-web tests/smoke/report-web.test.tsx pnpm-lock.yaml`
- `git commit -m "feat(report-web): add report shell renderer"`

